import os
import sys
import boto3

def prompt(msg, default=None):
    if default is not None:
        msg = f"{msg} [{default}]: "
    else:
        msg = f"{msg}: "
    s = input(msg).strip()
    return s if s else default

def iter_endpoints_from_stdin():
    print("Enter HTTPS endpoints (one per line). Blank line to finish.")
    while True:
        line = sys.stdin.readline()
        if not line:
            break
        line = line.strip()
        if not line:
            break
        yield line

def main():
    topic_arn = os.environ.get("SNS_TOPIC_ARN") or prompt("SNS TopicArn")
    region = os.environ.get("AWS_REGION") or os.environ.get("AWS_DEFAULT_REGION") or prompt("AWS region", "us-east-1")

    session = boto3.session.Session(region_name=region)
    sns = session.client("sns")

    endpoints = list(iter_endpoints_from_stdin())
    if not endpoints:
        print("No endpoints provided.")
        return 1

    results = []
    for endpoint in endpoints:
        resp = sns.subscribe(
            TopicArn=topic_arn,
            Protocol="https",
            Endpoint=endpoint
        )
        results.append((endpoint, resp.get("SubscriptionArn")))
        print(f"{endpoint}\t{resp.get('SubscriptionArn')}")

    return 0

if __name__ == "__main__":
    raise SystemExit(main())